// Key Generation
func generatePrivateKey() -> String {
    let privateKey = secp256k1.generatePrivateKey()
    return privateKey.toHexString()
}

func getPublicKey(from privateKey: String) -> String {
    guard let privateKeyData = Data(hexString: privateKey) else { return "" }
    let publicKey = secp256k1.publicKey(fromPrivateKey: privateKeyData)
    return publicKey.toHexString()
}

